381→**Step 3: Expand `handleChannelNotify` to emit system messages**
382→
383→In `src/wow/world-handlers.ts`, replace the `handleChannelNotify` function:
384→
385→```typescript
386→export function handleChannelNotify(conn: WorldConn, r: PacketReader): void {
387→  const event = parseChannelNotify(r);
388→  if (event.type === "joined") {
389→    conn.channels.push(event.channel);
390→    conn.onMessage?.({
391→      type: ChatType.SYSTEM,
392→      sender: "",
393→      message: `Joined channel: ${event.channel}`,
394→    });
395→  } else if (event.type === "left") {
396→    const idx = conn.channels.indexOf(event.channel);
397→    if (idx !== -1) conn.channels.splice(idx, 1);
398→    conn.onMessage?.({
399→      type: ChatType.SYSTEM,
400→      sender: "",
401→      message: `Left channel: ${event.channel}`,
402→    });
403→  } else if (event.type === "error") {
404→    conn.onMessage?.({
405→      type: ChatType.SYSTEM,
406→      sender: "",
407→      message: event.message,
408→    });
409→  }
410→}
411→```
