430→export function lookupCachedName(
431→  conn: WorldConn,
432→  guid: bigint,
433→  objectType: number,
434→  entry: number | undefined,
435→): string | undefined {
436→  if (objectType === ObjectType.PLAYER) {
437→    const guidLow = Number(guid & 0xffffffffn);
438→    return conn.nameCache.get(guidLow);
439→  }
440→  if (entry === undefined) return undefined;
441→  if (objectType === ObjectType.UNIT) return conn.creatureNameCache.get(entry);
442→  if (objectType === ObjectType.GAMEOBJECT)
443→    return conn.gameObjectNameCache.get(entry);
444→  return undefined;
