447→export function queryEntityName(
448→  conn: WorldConn,
449→  guid: bigint,
450→  objectType: number,
451→  entry: number | undefined,
452→): void {
453→  if (objectType === ObjectType.PLAYER) {
454→    const guidLow = Number(guid & 0xffffffffn);
455→    const key = `player:${guidLow}`;
456→    if (conn.pendingNameQueries.has(key)) return;
457→    conn.pendingNameQueries.add(key);
458→    const w = new PacketWriter();
459→    w.uint64LE(guid);
460→    sendPacket(conn, GameOpcode.CMSG_NAME_QUERY, w.finish());
461→    return;
462→  }
463→  if (entry === undefined) return;
464→  const key = `${objectType}:${entry}`;
465→  if (conn.pendingNameQueries.has(key)) return;
466→  conn.pendingNameQueries.add(key);
467→  if (objectType === ObjectType.UNIT) {
468→    sendPacket(
469→      conn,
470→      GameOpcode.CMSG_CREATURE_QUERY,
471→      buildCreatureQuery(entry, guid),
472→    );
473→    return;
474→  }
475→  if (objectType === ObjectType.GAMEOBJECT) {
476→    sendPacket(
477→      conn,
478→      GameOpcode.CMSG_GAMEOBJECT_QUERY,
479→      buildGameObjectQuery(entry, guid),
480→    );
481→    return;
482→  }
483→}
