  8→  | { type: "emote"; message: string }
  9→  | { type: "dnd"; message: string }
 10→  | { type: "afk"; message: string }
 11→  | { type: "whisper"; target: string; message: string }
 12→  | { type: "reply"; message: string }
 13→  | { type: "channel"; target: string; message: string }
 14→  | { type: "who"; target?: string }
 15→  | { type: "invite"; target: string }
 16→  | { type: "kick"; target: string }
 17→  | { type: "leave" }
 18→  | { type: "leader"; target: string }
 19→  | { type: "accept" }
 20→  | { type: "decline" }
 21→  | { type: "quit" }
 22→  | { type: "tuicraft"; subcommand: string; value: string }
 23→  | { type: "friends" }
 24→  | { type: "add-friend"; target: string }
 25→  | { type: "remove-friend"; target: string }
 26→  | { type: "roll"; min: number; max: number }
 27→  | { type: "ignored" }
 28→  | { type: "add-ignore"; target: string }
 29→  | { type: "remove-ignore"; target: string }
 30→  | { type: "unimplemented"; feature: string };
 31→
 32→export function parseCommand(input: string): Command {
 33→  if (!input.startsWith("/")) return { type: "chat", message: input };
 34→
 35→  const spaceIdx = input.indexOf(" ");
 36→  const cmd = spaceIdx === -1 ? input : input.slice(0, spaceIdx);
 37→  const rest = spaceIdx === -1 ? "" : input.slice(spaceIdx + 1);
 38→
 39→  switch (cmd) {
 40→    case "/s":
 41→    case "/say":
 42→      return { type: "say", message: rest };
 43→    case "/y":
 44→    case "/yell":
 45→      return { type: "yell", message: rest };
 46→    case "/g":
 47→    case "/guild":
 48→      return { type: "guild", message: rest };
 49→    case "/p":
 50→    case "/party":
 51→      return { type: "party", message: rest };
 52→    case "/raid":
 53→      return { type: "raid", message: rest };
 54→    case "/w":
 55→    case "/whisper": {
 56→      const targetEnd = rest.indexOf(" ");
 57→      if (targetEnd === -1)
 58→        return { type: "whisper", target: rest, message: "" };
 59→      return {
 60→        type: "whisper",
 61→        target: rest.slice(0, targetEnd),
 62→        message: rest.slice(targetEnd + 1),
 63→      };
 64→    }
 65→    case "/r":
 66→      return { type: "reply", message: rest };
 67→    case "/who":
 68→      return rest ? { type: "who", target: rest } : { type: "who" };
 69→    case "/invite":
 70→      return rest
 71→        ? { type: "invite", target: rest }
 72→        : { type: "say", message: input };
 73→    case "/kick":
 74→      return rest
 75→        ? { type: "kick", target: rest }
 76→        : { type: "say", message: input };
 77→    case "/leave":
 78→      return { type: "leave" };
 79→    case "/leader":
 80→      return rest
 81→        ? { type: "leader", target: rest }
 82→        : { type: "say", message: input };
 83→    case "/accept":
 84→      return { type: "accept" };
 85→    case "/decline":
 86→      return { type: "decline" };
 87→    case "/quit":
 88→      return { type: "quit" };
 89→    case "/tuicraft": {
 90→      const parts = rest.split(" ");
 91→      return {
 92→        type: "tuicraft",
 93→        subcommand: parts[0] ?? "",
 94→        value: parts[1] ?? "",
 95→      };
 96→    }
 97→    case "/friends":
 98→      return { type: "friends" };
 99→    case "/f":
100→      return { type: "friends" };
101→    case "/friend": {
102→      const parts = rest.split(" ");
103→      const sub = parts[0] ?? "";
104→      const target = parts.slice(1).join(" ");
105→      if (sub === "add" && target) return { type: "add-friend", target };
106→      if (sub === "remove" && target) return { type: "remove-friend", target };
107→      return { type: "friends" };
108→    }
109→    case "/ignore":
110→      return rest ? { type: "add-ignore", target: rest } : { type: "ignored" };
111→    case "/unignore":
112→      return rest
113→        ? { type: "remove-ignore", target: rest }
114→        : { type: "say", message: input };
115→    case "/ignorelist":
116→      return { type: "ignored" };
117→    case "/join":
118→      return { type: "unimplemented", feature: "Channel join/leave" };
119→    case "/ginvite":
120→    case "/gkick":
121→    case "/gleave":
122→    case "/gpromote":
123→      return { type: "unimplemented", feature: "Guild management" };
124→    case "/mail":
125→      return { type: "unimplemented", feature: "Mail" };
126→    case "/roll": {
127→      const parts = rest.split(" ").filter(Boolean);
128→      if (parts.length >= 2)
129→        return {
130→          type: "roll",
131→          min: parseInt(parts[0]!, 10),
132→          max: parseInt(parts[1]!, 10),
133→        };
134→      if (parts.length === 1)
135→        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
136→      return { type: "roll", min: 1, max: 100 };
137→    }
138→    case "/dnd":
139→      return { type: "dnd", message: rest };
140→    case "/afk":
141→      return { type: "afk", message: rest };
142→    case "/e":
143→    case "/emote":
144→      return { type: "emote", message: rest };
145→  }
146→
147→  const channelMatch = cmd.match(/^\/(\d+)$/);
148→  return channelMatch
149→    ? { type: "channel", target: channelMatch[1]!, message: rest }
150→    : { type: "say", message: input };
151→}
