import { test, expect, describe } from "bun:test";
import { parseCommand } from "ui/commands";

describe("parseCommand", () => {
  test("bare text becomes chat", () => {
    expect(parseCommand("hello")).toEqual({ type: "chat", message: "hello" });
  });

