 39→export type IpcCommand =
 40→  | { type: "chat"; message: string }
 41→  | { type: "say"; message: string }
 42→  | { type: "yell"; message: string }
 43→  | { type: "guild"; message: string }
 44→  | { type: "party"; message: string }
 45→  | { type: "emote"; message: string }
 46→  | { type: "dnd"; message: string }
 47→  | { type: "afk"; message: string }
 48→  | { type: "whisper"; target: string; message: string }
 49→  | { type: "read" }
 50→  | { type: "read_json" }
 51→  | { type: "read_wait"; ms: number }
 52→  | { type: "read_wait_json"; ms: number }
 53→  | { type: "stop" }
 54→  | { type: "status" }
 55→  | { type: "who"; filter?: string }
 56→  | { type: "who_json"; filter?: string }
 57→  | { type: "invite"; target: string }
 58→  | { type: "kick"; target: string }
 59→  | { type: "leave" }
 60→  | { type: "leader"; target: string }
 61→  | { type: "accept" }
 62→  | { type: "decline" }
 63→  | { type: "nearby" }
 64→  | { type: "nearby_json" }
 65→  | { type: "friends" }
 66→  | { type: "friends_json" }
 67→  | { type: "add_friend"; target: string }
 68→  | { type: "del_friend"; target: string }
 69→  | { type: "ignored" }
 70→  | { type: "ignored_json" }
 71→  | { type: "add_ignore"; target: string }
 72→  | { type: "del_ignore"; target: string }
 73→  | { type: "roll"; min: number; max: number }
 74→  | { type: "unimplemented"; feature: string };
 75→
 76→export function parseIpcCommand(line: string): IpcCommand | undefined {
 77→  if (line.startsWith("/")) {
 78→    const parsed = parseCommand(line);
 79→    switch (parsed.type) {
 80→      case "say":
 81→      case "yell":
 82→      case "guild":
 83→      case "party":
 84→      case "emote":
 85→      case "dnd":
 86→      case "afk":
 87→        return parsed;
 88→      case "whisper":
 89→        return parsed;
 90→      case "who":
 91→        return parsed.target
 92→          ? { type: "who", filter: parsed.target }
 93→          : { type: "who" };
 94→      case "invite":
 95→      case "kick":
 96→      case "leave":
 97→      case "leader":
 98→      case "accept":
 99→      case "decline":
100→        return parsed;
101→      case "friends":
102→        return { type: "friends" };
103→      case "add-friend":
104→        return { type: "add_friend", target: parsed.target };
105→      case "remove-friend":
106→        return { type: "del_friend", target: parsed.target };
107→      case "ignored":
108→        return { type: "ignored" };
109→      case "add-ignore":
110→        return { type: "add_ignore", target: parsed.target };
111→      case "remove-ignore":
112→        return { type: "del_ignore", target: parsed.target };
113→      case "roll":
114→        return parsed;
115→      case "unimplemented":
116→        return parsed;
117→      default:
118→        return { type: "say", message: line };
119→    }
120→  }
121→
122→  const spaceIdx = line.indexOf(" ");
123→  const verb = spaceIdx === -1 ? line : line.slice(0, spaceIdx);
124→  const rest = spaceIdx === -1 ? "" : line.slice(spaceIdx + 1);
125→
126→  switch (verb) {
127→    case "SAY":
128→    case "YELL":
129→    case "GUILD":
130→    case "PARTY":
131→    case "EMOTE":
132→    case "DND":
133→    case "AFK":
134→      return {
135→        type: verb.toLowerCase() as
136→          | "say"
137→          | "yell"
138→          | "guild"
139→          | "party"
140→          | "emote"
141→          | "dnd"
142→          | "afk",
143→        message: rest,
144→      };
145→    case "WHISPER": {
146→      const targetEnd = rest.indexOf(" ");
147→      if (targetEnd === -1)
148→        return { type: "whisper", target: rest, message: "" };
149→      return {
150→        type: "whisper",
151→        target: rest.slice(0, targetEnd),
152→        message: rest.slice(targetEnd + 1),
153→      };
154→    }
155→    case "READ":
156→      return { type: "read" };
157→    case "READ_JSON":
158→      return { type: "read_json" };
159→    case "READ_WAIT": {
160→      const ms = parseInt(rest, 10);
161→      if (!Number.isFinite(ms) || ms < 0) return undefined;
162→      return { type: "read_wait", ms: Math.min(ms, 60_000) };
163→    }
164→    case "READ_WAIT_JSON": {
165→      const ms = parseInt(rest, 10);
166→      if (!Number.isFinite(ms) || ms < 0) return undefined;
167→      return { type: "read_wait_json", ms: Math.min(ms, 60_000) };
168→    }
169→    case "STOP":
170→      return { type: "stop" };
171→    case "STATUS":
172→      return { type: "status" };
173→    case "WHO":
174→      return rest ? { type: "who", filter: rest } : { type: "who" };
175→    case "WHO_JSON":
176→      return rest ? { type: "who_json", filter: rest } : { type: "who_json" };
177→    case "INVITE":
178→      return rest ? { type: "invite", target: rest } : undefined;
179→    case "KICK":
180→      return rest ? { type: "kick", target: rest } : undefined;
181→    case "LEAVE":
182→      return { type: "leave" };
183→    case "LEADER":
184→      return rest ? { type: "leader", target: rest } : undefined;
185→    case "ACCEPT":
186→      return { type: "accept" };
187→    case "DECLINE":
188→      return { type: "decline" };
189→    case "NEARBY":
190→      return { type: "nearby" };
191→    case "NEARBY_JSON":
192→      return { type: "nearby_json" };
193→    case "FRIENDS":
194→      return { type: "friends" };
195→    case "FRIENDS_JSON":
196→      return { type: "friends_json" };
197→    case "ADD_FRIEND":
198→      return rest ? { type: "add_friend", target: rest } : undefined;
199→    case "DEL_FRIEND":
200→      return rest ? { type: "del_friend", target: rest } : undefined;
201→    case "IGNORED":
202→      return { type: "ignored" };
203→    case "IGNORED_JSON":
204→      return { type: "ignored_json" };
205→    case "ADD_IGNORE":
206→      return rest ? { type: "add_ignore", target: rest } : undefined;
207→    case "DEL_IGNORE":
208→      return rest ? { type: "del_ignore", target: rest } : undefined;
209→    case "JOIN":
210→      return { type: "unimplemented", feature: "Channel join/leave" };
211→    case "GINVITE":
212→    case "GKICK":
213→    case "GLEAVE":
214→    case "GPROMOTE":
215→      return { type: "unimplemented", feature: "Guild management" };
216→    case "MAIL":
217→      return { type: "unimplemented", feature: "Mail" };
218→    case "ROLL": {
219→      const parts = rest.split(" ").filter(Boolean);
220→      if (parts.length >= 2)
221→        return {
222→          type: "roll",
223→          min: parseInt(parts[0]!, 10),
224→          max: parseInt(parts[1]!, 10),
225→        };
226→      if (parts.length === 1)
227→        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
228→      return { type: "roll", min: 1, max: 100 };
229→    }
230→    default:
231→      return line ? { type: "chat", message: line } : undefined;
232→  }
233→}
