258→export async function dispatchCommand(
259→  cmd: IpcCommand,
260→  handle: WorldHandle,
261→  events: RingBuffer<EventEntry>,
262→  socket: IpcSocket,
263→  cleanup: () => void,
264→): Promise<boolean> {
265→  switch (cmd.type) {
266→    case "chat": {
267→      handle.sendInCurrentMode(cmd.message);
268→      const mode = handle.getLastChatMode();
269→      const label =
270→        mode.type === "whisper"
271→          ? `WHISPER ${mode.target}`
272→          : mode.type === "channel"
273→            ? `CHANNEL ${mode.channel}`
274→            : mode.type.toUpperCase();
275→      writeLines(socket, [`OK ${label}`]);
276→      return false;
277→    }
278→    case "say":
279→      handle.sendSay(cmd.message);
280→      writeLines(socket, ["OK"]);
281→      return false;
282→    case "yell":
283→      handle.sendYell(cmd.message);
284→      writeLines(socket, ["OK"]);
285→      return false;
286→    case "guild":
287→      handle.sendGuild(cmd.message);
288→      writeLines(socket, ["OK"]);
289→      return false;
290→    case "party":
291→      handle.sendParty(cmd.message);
292→      writeLines(socket, ["OK"]);
293→      return false;
294→    case "emote":
295→      handle.sendEmote(cmd.message);
296→      writeLines(socket, ["OK"]);
297→      return false;
298→    case "dnd":
299→      handle.sendDnd(cmd.message);
300→      writeLines(socket, ["OK"]);
301→      return false;
302→    case "afk":
303→      handle.sendAfk(cmd.message);
304→      writeLines(socket, ["OK"]);
305→      return false;
306→    case "whisper":
307→      handle.sendWhisper(cmd.target, cmd.message);
308→      writeLines(socket, ["OK"]);
309→      return false;
310→    case "roll":
311→      handle.sendRoll(cmd.min, cmd.max);
312→      writeLines(socket, ["OK"]);
313→      return false;
314→    case "read":
315→      writeLines(socket, drainText(events));
316→      return false;
317→    case "read_json":
318→      writeLines(socket, drainJson(events));
319→      return false;
320→    case "read_wait": {
321→      const start = events.writePos;
322→      await new Promise<void>((resolve) => {
323→        setTimeout(() => {
324→          writeLines(socket, sliceText(events, start));
325→          resolve();
326→        }, cmd.ms);
327→      });
328→      return false;
329→    }
330→    case "read_wait_json": {
331→      const start = events.writePos;
332→      await new Promise<void>((resolve) => {
333→        setTimeout(() => {
334→          writeLines(socket, sliceJson(events, start));
335→          resolve();
336→        }, cmd.ms);
337→      });
338→      return false;
339→    }
340→    case "stop":
341→      writeLines(socket, ["OK"]);
342→      cleanup();
343→      return true;
344→    case "status":
345→      writeLines(socket, ["CONNECTED"]);
346→      return false;
347→    case "who": {
348→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
349→      writeLines(socket, formatWhoResults(results).split("\n"));
350→      return false;
351→    }
352→    case "who_json": {
353→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
354→      writeLines(socket, [formatWhoResultsJson(results)]);
355→      return false;
356→    }
357→    case "invite":
358→      handle.invite(cmd.target);
359→      writeLines(socket, ["OK"]);
360→      return false;
361→    case "kick":
362→      handle.uninvite(cmd.target);
363→      writeLines(socket, ["OK"]);
364→      return false;
365→    case "leave":
366→      handle.leaveGroup();
367→      writeLines(socket, ["OK"]);
368→      return false;
369→    case "leader":
370→      handle.setLeader(cmd.target);
371→      writeLines(socket, ["OK"]);
372→      return false;
373→    case "accept":
374→      handle.acceptInvite();
375→      writeLines(socket, ["OK"]);
376→      return false;
377→    case "decline":
378→      handle.declineInvite();
379→      writeLines(socket, ["OK"]);
380→      return false;
381→    case "nearby": {
382→      const entities = handle.getNearbyEntities();
383→      writeLines(socket, entities.map(formatNearbyLine));
384→      return false;
385→    }
386→    case "nearby_json": {
387→      const entities = handle.getNearbyEntities();
388→      writeLines(
389→        socket,
390→        entities.map((e) => JSON.stringify(formatNearbyObj(e))),
391→      );
392→      return false;
393→    }
394→    case "friends": {
395→      const friends = handle.getFriends();
396→      writeLines(socket, formatFriendList(friends).split("\n"));
397→      return false;
398→    }
399→    case "friends_json": {
400→      const friends = handle.getFriends();
401→      writeLines(socket, [formatFriendListJson(friends)]);
402→      return false;
403→    }
404→    case "add_friend":
405→      handle.addFriend(cmd.target);
406→      writeLines(socket, ["OK"]);
407→      return false;
408→    case "del_friend":
409→      handle.removeFriend(cmd.target);
410→      writeLines(socket, ["OK"]);
411→      return false;
412→    case "ignored": {
413→      const ignored = handle.getIgnored();
414→      writeLines(socket, formatIgnoreList(ignored).split("\n"));
415→      return false;
416→    }
417→    case "ignored_json": {
418→      const ignored = handle.getIgnored();
419→      writeLines(socket, [formatIgnoreListJson(ignored)]);
420→      return false;
421→    }
422→    case "add_ignore":
423→      handle.addIgnore(cmd.target);
424→      writeLines(socket, ["OK"]);
425→      return false;
426→    case "del_ignore":
427→      handle.removeIgnore(cmd.target);
428→      writeLines(socket, ["OK"]);
429→      return false;
430→    case "unimplemented":
431→      writeLines(socket, [`UNIMPLEMENTED ${cmd.feature}`]);
432→      return false;
433→  }
434→}
