576→): void {
577→  const text = formatEntityEvent(event);
578→  const obj = formatEntityEventObj(event);
579→  if (obj) {
580→    events.push({ text, json: JSON.stringify(obj) });
581→    log.append(obj as LogEntry).catch(() => {});
582→  }
583→}
584→
