  [ChannelNotify.INVALID_NAME]: () => "Invalid channel name",
  [ChannelNotify.THROTTLED]: (ch) => `Channel message throttled in ${ch}`,
  [ChannelNotify.NOT_IN_AREA]: (ch) =>
    `You are not in the correct area for ${ch}`,
};

