  const closed = new Promise<void>((r) => {
    closeResolve = r;
  });
  let lastChatMode: ChatMode = { type: "say" };

  return {
    closed,
    close: jest.fn(() => closeResolve()),
    onMessage(cb) {
      messageCb = cb;
    },
    sendWhisper: jest.fn(),
    sendSay: jest.fn(),
    sendYell: jest.fn(),
    sendGuild: jest.fn(),
    sendParty: jest.fn(),
    sendRaid: jest.fn(),
    sendEmote: jest.fn(),
    sendDnd: jest.fn(),
    sendAfk: jest.fn(),
    sendChannel: jest.fn(),
    getChannel: jest.fn(),
    who: jest.fn(async () => []),
    getLastChatMode: jest.fn(() => lastChatMode),
    setLastChatMode: jest.fn((mode: ChatMode) => {
      lastChatMode = mode;
    }),
    sendInCurrentMode: jest.fn(),
    invite: jest.fn(),
    uninvite: jest.fn(),
    leaveGroup: jest.fn(),
    setLeader: jest.fn(),
    acceptInvite: jest.fn(),
    declineInvite: jest.fn(),
    onGroupEvent(cb) {
      groupEventCb = cb;
    },
    onEntityEvent(cb) {
      entityEventCb = cb;
    },
    onPacketError: jest.fn(),
    getNearbyEntities: jest.fn((): Entity[] => []),
    getFriends: jest.fn((): FriendEntry[] => []),
    addFriend: jest.fn(),
    removeFriend: jest.fn(),
    sendRoll: jest.fn(),
    onFriendEvent(cb) {
      friendEventCb = cb;
    },
    getIgnored: jest.fn((): IgnoreEntry[] => []),
    addIgnore: jest.fn(),
    removeIgnore: jest.fn(),
    onIgnoreEvent(cb) {
      ignoreEventCb = cb;
    },
    triggerMessage(msg) {
      messageCb?.(msg);
    },
    triggerGroupEvent(event) {
      groupEventCb?.(event);
    },
    triggerEntityEvent(event) {
      entityEventCb?.(event);
    },
    triggerFriendEvent(event) {
      friendEventCb?.(event);
    },
    triggerIgnoreEvent(event) {
      ignoreEventCb?.(event);
    },
    resolveClosed() {
      closeResolve();
    },
  };
}

import { mock, jest, test, expect, describe, afterEach } from "bun:test";
import { access, rm, mkdir, unlink } from "node:fs/promises";
import { serializeConfig } from "lib/config";
import type { AuthResult } from "wow/auth";
import type { WorldHandle } from "wow/client";
import { sendToSocket } from "cli/ipc";

const tmpDir = `./tmp/daemon-start-${Date.now()}`;
const cfgDir = `${tmpDir}/config/tuicraft`;
const uid = process.getuid?.() ?? 0;
const rtDir = `${tmpDir}/tuicraft-${uid}`;
const stDir = `${tmpDir}/state/tuicraft`;

mock.module("lib/paths", () => ({
  configDir: () => cfgDir,
  runtimeDir: () => rtDir,
  stateDir: () => stDir,
  socketPath: () => `${rtDir}/sock`,
  pidPath: () => `${rtDir}/pid`,
  configPath: () => `${cfgDir}/config.toml`,
  logPath: () => `${stDir}/session.log`,
}));

let closedResolve: () => void;

function makeMockClient(): {
  authHandshake: ReturnType<typeof jest.fn>;
  worldSession: ReturnType<typeof jest.fn>;
  mockHandleClose: ReturnType<typeof jest.fn>;
} {
  const mockHandleClose = jest.fn();
  const closed = new Promise<void>((r) => {
    closedResolve = r;
  });
  return {
    authHandshake: jest.fn(
      async (): Promise<AuthResult> => ({
        sessionKey: new Uint8Array(40),
        realmHost: "localhost",
        realmPort: 8085,
        realmId: 1,
      }),
    ),
    worldSession: jest.fn(
      async (): Promise<WorldHandle> => ({
        closed,
        close: mockHandleClose,
        onMessage: jest.fn(),
        sendSay: jest.fn(),
        sendYell: jest.fn(),
        sendGuild: jest.fn(),
        sendParty: jest.fn(),
        sendRaid: jest.fn(),
        sendEmote: jest.fn(),
        sendDnd: jest.fn(),
        sendAfk: jest.fn(),
        sendWhisper: jest.fn(),
        sendChannel: jest.fn(),
        getChannel: jest.fn(),
        who: jest.fn(async () => []),
        getLastChatMode: jest.fn(() => ({ type: "say" as const })),
        setLastChatMode: jest.fn(),
        sendInCurrentMode: jest.fn(),
        invite: jest.fn(),
        uninvite: jest.fn(),
        leaveGroup: jest.fn(),
        setLeader: jest.fn(),
        acceptInvite: jest.fn(),
        declineInvite: jest.fn(),
        onGroupEvent: jest.fn(),
        onEntityEvent: jest.fn(),
