        factionTemplate: 0,
        displayId: 0,
        npcFlags: 0,
        unitFlags: 0,
        target: 0n,
        race: 0,
        class_: 0,
        gender: 0,
        power: [0, 0, 0, 0, 0, 0, 0],
        maxPower: [0, 0, 0, 0, 0, 0, 0],
      } satisfies UnitEntity,
