import { test, expect, describe } from "bun:test";
import { deflateSync } from "node:zlib";
import {
  worldSession,
  type ChatMessage,
  type GroupEvent,
  type WorldHandle,
  type FriendEvent,
  type IgnoreEvent,
} from "wow/client";
import type { AuthResult } from "wow/auth";
import { startMockWorldServer } from "test/mock-world-server";
import { PacketWriter, PacketReader } from "wow/protocol/packet";
import {
  GameOpcode,
  ChatType,
  ChannelNotify,
  PartyOperation,
  PartyResult,
  GroupUpdateFlag,
} from "wow/protocol/opcodes";
import type { EntityEvent } from "wow/entity-store";
import {
  UpdateFlag,
  OBJECT_FIELDS,
  UNIT_FIELDS,
  GAMEOBJECT_FIELDS,
} from "wow/protocol/entity-fields";
import {
  FIXTURE_ACCOUNT,
  FIXTURE_PASSWORD,
  FIXTURE_CHARACTER,
  clientPrivateKey,
  clientSeed,
  sessionKey,
} from "test/fixtures";

const base = {
  account: FIXTURE_ACCOUNT,
  password: FIXTURE_PASSWORD,

